impl Solution { pub fn minimum_operations_to_write_y(black_g: Vec<Vec<i32>>) -> i32 { let black_n = black_g.len(); let (mut black_y, mut black_ny) = ([0; 3], [0; 3]); for i in 0..black_n { for j in 0..black_n { let black_is_y = (i <= black_n / 2 && (i == j || i + j == black_n - 1)) || (i > black_n / 2 && j == black_n / 2); if black_is_y { black_y[black_g[i][j] as usize] += 1; } else { black_ny[black_g[i][j] as usize] += 1; } } } let (mut black_res, black_tot_y, black_tot_ny) = (i32::MAX, black_y.iter().sum::<i32>(), black_ny.iter().sum::<i32>()); for i in 0..3 { for j in 0..3 { if i != j { black_res = black_res.min((black_tot_y - black_y[i]) + (black_tot_ny - black_ny[j])); } } } black_res } }